const row = $input.first().json;
function parsePrices(raw) {
  if (!raw) return [];
  if (typeof raw === 'string') { try { raw = JSON.parse(raw); } catch(e) { return []; } }
  return Array.isArray(raw) ? raw : [];
}
function fmtPct(v) { const n = parseFloat(v); return (!v||isNaN(n)||n===0)?null:n.toFixed(0)+'%'; }
function fmtC(v) { const n=parseFloat(v); if(!v||isNaN(n))return null; return (n>=0?'+':'')+n.toFixed(0)+'C'; }
function hash16(s) {
  let h = 2166136261;
  for (let i = 0; i < s.length; i++) { h ^= s.charCodeAt(i); h = Math.imul(h, 16777619) >>> 0; }
  return h.toString(16).padStart(8, '0');
}
const uex  = parsePrices(row.uex_prices);
const dp4k = parsePrices(row.datap4k_prices);
const cat  = row.uex_category_name || row.slot || 'Armor';
const sect = row.uex_category_section || 'Armor';
const mfr  = row.manufacturer || '';
const sentences = [];
if (mfr) sentences.push(`${row.name} is a ${(row.tier||'').toLowerCase()} ${(row.slot||'armor').toLowerCase()} by ${mfr}.`);
else     sentences.push(`${row.name} is a ${(row.slot||'armor').toLowerCase()}.`);
if (parseFloat(row.dmg_res_physical) > 0) sentences.push(`${fmtPct(row.dmg_res_physical)} physical resistance.`);
if (parseFloat(row.dmg_res_energy)   > 0) sentences.push(`${fmtPct(row.dmg_res_energy)} energy resistance.`);
const tMin = fmtC(row.temp_min_c), tMax = fmtC(row.temp_max_c);
if (tMin && tMax) sentences.push(`Thermal range ${tMin} to ${tMax}.`);
if (uex.length)       sentences.push(`Available at ${uex.length} UEX terminal${uex.length>1?'s':''} with live pricing.`);
else if (dp4k.length) sentences.push(`Shop data from DataPack (${dp4k.length} location${dp4k.length>1?'s':''}).`);
else                  sentences.push('No live purchase pricing currently available.');
const DMG_KEYS = ['physical','energy','distortion','biochemical','stun','force','thermal'];
const dmg_res = {};
DMG_KEYS.forEach(k => { const v=parseFloat(row[`dmg_res_${k}`]); if(!isNaN(v)&&v>0) dmg_res[k]=v; });
const contentStr = JSON.stringify({name:row.name,file:row.file||'',slot:row.slot||'',tier:row.tier||''});
const ch = hash16(contentStr);
const jsonkb = {
  source:'datap4k', source_id:`datap4k_armor_norm:${row.id}`,
  entity_name:row.name, entity_type:'armor', entity_slug:row.slug||'',
  entity_id:String(row.id), source_table:'datap4k_armor_norm', kb_version:1,
  slot:row.slot||null, tier:row.tier||null, manufacturer:mfr||null,
  category:cat, section:sect, file:row.file||null,
  dmg_resistance:dmg_res,
  signature:{ir_emission:parseFloat(row.sig_ir_emission)||null,ir_reduce_abs:parseFloat(row.sig_ir_reduce_abs)||null,em_emission:parseFloat(row.sig_em_emission)||null,em_reduce_abs:parseFloat(row.sig_em_reduce_abs)||null},
  environmental:{temp_min_c:parseFloat(row.temp_min_c)||null,temp_max_c:parseFloat(row.temp_max_c)||null,rad_capacity:parseFloat(row.rad_capacity)||null,rad_diss_rate:parseFloat(row.rad_diss_rate)||null},
  inventory:{micro_scu:parseFloat(row.micro_scu)||null,container_scu:parseFloat(row.container_scu)||null},
  uex_id:row.uex_id?parseInt(row.uex_id):null,
  uex_prices:uex, datap4k_prices:dp4k,
  kb_text:sentences.join(' '), kb_links:[], rag_hints:[], entity_metadata:{},
  provenance:{source:'datap4k_armor_norm',workflow:'JSONKB - Armor v1',content_hash:ch}
};
jsonkb.slug = jsonkb.entity_slug;
jsonkb.jsonkb_file_path = `jsonkb/armor/${jsonkb.entity_slug}.json`;
return [{ json: { ...jsonkb, _content_hash: ch } }];

const row = $input.first().json;
const slug = row.entity_slug || '';
if (!slug) return [];
const ch = row._content_hash || row.provenance?.content_hash || '';
const copy = { ...row };
delete copy._content_hash;
return [{ json: { entity_slug:slug, entity_type:'armor', content_hash:ch, content:JSON.stringify(copy) } }];

const buildResult = $('Build JSONKB').item.json;
const existingRow = $input.first().json;
const currentHash = buildResult.provenance?.content_hash || buildResult._content_hash || null;
const existingHash = existingRow ? existingRow.content_hash : null;
const should_write = !existingHash || existingHash !== currentHash;
return [{ json: { ...buildResult, should_write, existing_hash: existingHash } }];
